func accessURLForObject(filesystem RouteFileSystem, drsConfig *drs_support.DrsConfig, objectID string, accessID string, object *drs_support.InternalDrsObject) (*AccessUrl, int, error) {
	if filesystem == nil {
		return nil, http.StatusInternalServerError, fmt.Errorf("missing iRODS filesystem")
	}
	if drsConfig == nil {
		return nil, http.StatusInternalServerError, fmt.Errorf("missing DRS config")
	}
	if object == nil {
		return nil, http.StatusInternalServerError, fmt.Errorf("missing DRS object")
	}

	switch strings.TrimSpace(accessID) {
	case compoundManifestHTTPSAccessID:
		if !object.IsManifest {
			return nil, http.StatusNotFound, fmt.Errorf("access id %q not found for object %q", accessID, objectID)
		}
		url, err := buildPublicAbsoluteURL(drsConfig, "/ga4gh/drs/v1/ext/compound/"+neturl.PathEscape(strings.TrimSpace(objectID)))
		if err != nil {
			return nil, http.StatusInternalServerError, fmt.Errorf("build compound manifest access URL for object %q: %w", objectID, err)
		}
		return &AccessUrl{Url: url}, http.StatusOK, nil
	case "irods":
		return buildIRODSAccessURL(filesystem, drsConfig, objectID, object)
	default:
		parsedAccessID, ok := drs_support.ParseHTTPSAccessID(accessID)
		if ok {
			return buildHTTPSProviderAccessURL(filesystem, drsConfig, objectID, object, parsedAccessID)
		}
		if existingType, found := accessMethodTypeByAccessID(drs_support.BuildAccessMethodsWithFilesystem(drsConfig, object, filesystem), accessID); found {
			return nil, http.StatusNotImplemented, fmt.Errorf("access id %q resolves to access method type %q, which is not supported by /access in this deployment", accessID, existingType)
		}
		return nil, http.StatusNotFound, fmt.Errorf("access id %q not found for object %q", accessID, objectID)
	}
}

func accessMethodTypeByAccessID(methods []drs_support.DrsAccessMethod, accessID string) (string, bool) {
	accessID = strings.TrimSpace(accessID)
	if accessID == "" || len(methods) == 0 {
		return "", false
	}

	for _, method := range methods {
		if strings.TrimSpace(method.AccessID) != accessID {
			continue
		}

		methodType := strings.TrimSpace(method.Type)
		if methodType == "" {
			methodType = "unknown"
		}
		return methodType, true
	}

	return "", false
}

func buildHTTPSProviderAccessURL(filesystem RouteFileSystem, drsConfig *drs_support.DrsConfig, objectID string, object *drs_support.InternalDrsObject, parsedAccessID drs_support.ParsedHTTPSAccessID) (*AccessUrl, int, error) {
	if !drsConfig.HttpsAccessMethodSupported {
		return nil, http.StatusNotImplemented, fmt.Errorf("https access method is not enabled")
	}
	configuredProvider := drs_support.EffectiveHTTPSAccessProvider(drsConfig.HttpsAccessImplementation)
	if !drs_support.IsSupportedHTTPSAccessProvider(configuredProvider) {
		return nil, http.StatusNotImplemented, fmt.Errorf("unsupported https access provider %q", strings.TrimSpace(drsConfig.HttpsAccessImplementation))
	}
	if parsedAccessID.Provider != configuredProvider {
		return nil, http.StatusNotFound, fmt.Errorf("access id provider %q does not match configured https provider %q", parsedAccessID.Provider, configuredProvider)
	}

	preferredHost := ""
	affinityResource := strings.TrimSpace(parsedAccessID.Resource)
	if affinityResource == "" {
		// Backward compatibility: default provider access IDs (without explicit
		// resource suffix) still resolve through resource affinity using the
		// object's primary replica resource.
		affinityResource = primaryReplicaResourceForAccess(object)
	}
	if affinityResource != "" {
		preferredHost = drs_support.ResolveAffinityHostForResource(drsConfig, affinityResource)
	}

	baseURL := drs_support.ResolveHTTPSAccessBaseURL(drsConfig.HttpsAccessMethodBaseURL, preferredHost)
	if baseURL == "" {
		return nil, http.StatusInternalServerError, fmt.Errorf("https access method base URL is not configured")
	}

	url := baseURL + neturl.QueryEscape(strings.TrimSpace(object.AbsolutePath))
	headers := []string{}

	if drsConfig.HttpsAccessUseTicket {
		ticketID, bearerToken, err := extension_tickets.CreateAnonymousDataObjectBearerToken(
			filesystem,
			object.AbsolutePath,
			int64(drsConfig.DefaultTicketUseLimit),
			drsConfig.DefaultTicketLifetimeMinutes,
		)
		if err != nil {
			return nil, http.StatusInternalServerError, fmt.Errorf("create access ticket for object %q: %w", objectID, err)
		}
		if strings.TrimSpace(ticketID) == "" {
			return nil, http.StatusInternalServerError, fmt.Errorf("created empty ticket id for object %q", objectID)
		}
		headers = append(headers, "Authorization: Bearer "+bearerToken)
	}

	return &AccessUrl{
		Url:     url,
		Headers: headers,
	}, http.StatusOK, nil
}

func primaryReplicaResourceForAccess(object *drs_support.InternalDrsObject) string {
	if object == nil {
		return ""
	}

	for _, replica := range object.Replicas {
		resourceName := strings.TrimSpace(replica.ResourceName)
		if resourceName != "" {
			return resourceName
		}
	}

	return strings.TrimSpace(object.ResourceName)
}

func buildIRODSAccessURL(filesystem RouteFileSystem, drsConfig *drs_support.DrsConfig, objectID string, object *drs_support.InternalDrsObject) (*AccessUrl, int, error) {
	if !drsConfig.IrodsAccessMethodSupported {
		return nil, http.StatusNotImplemented, fmt.Errorf("irods access method is not enabled")
	}

	host := strings.TrimSpace(drsConfig.IRODSAccessHost)
	if host == "" {
		host = strings.TrimSpace(drsConfig.IrodsHost)
	}
	if host == "" {
		if account := filesystem.GetAccount(); account != nil {
			host = strings.TrimSpace(account.Host)
		}
	}

	port := drsConfig.IRODSAccessPort
	if port == 0 {
		port = drsConfig.IrodsPort
	}
	if port <= 0 {
		if account := filesystem.GetAccount(); account != nil {
			port = account.Port
		}
	}

	zone := strings.TrimSpace(object.IrodsZone)
	if zone == "" {
		zone = strings.TrimSpace(drsConfig.IrodsZone)
	}

	if host == "" || port <= 0 {
		return nil, http.StatusInternalServerError, fmt.Errorf("irods access host and port must be configured")
	}
	if zone == "" {
		return nil, http.StatusInternalServerError, fmt.Errorf("irods zone must be configured for object %q", objectID)
	}
	if strings.TrimSpace(object.AbsolutePath) == "" {
		return nil, http.StatusInternalServerError, fmt.Errorf("irods absolute path is missing for object %q", objectID)
	}

	ticketID, _, err := extension_tickets.CreateAnonymousDataObjectBearerToken(
		filesystem,
		object.AbsolutePath,
		int64(drsConfig.DefaultTicketUseLimit),
		drsConfig.DefaultTicketLifetimeMinutes,
	)
	if err != nil {
		return nil, http.StatusInternalServerError, fmt.Errorf("create access ticket for object %q: %w", objectID, err)
	}
	if strings.TrimSpace(ticketID) == "" {
		return nil, http.StatusInternalServerError, fmt.Errorf("created empty ticket id for object %q", objectID)
	}

	uri, err := extension_irodsuri.BuildWithTicket(host, port, &extension_irodsuri.UserInfo{
		UserName: "anonymous",
		Zone:     zone,
	}, object.AbsolutePath, ticketID)
	if err != nil {
		return nil, http.StatusInternalServerError, fmt.Errorf("build irods access URI for object %q: %w", objectID, err)
	}

	return &AccessUrl{
		Url: uri.String(),
	}, http.StatusOK, nil
}

