func drsObjectFromInternal(r *http.Request, object *drs_support.InternalDrsObject, expand bool, filesystem drs_support.IRODSFilesystem) (DrsObject, error) {
	var accessMethods []AccessMethod
	var drsConfig *drs_support.DrsConfig
	if serviceContext, ok := DrsServiceContextFromContext(r.Context()); ok && serviceContext != nil {
		drsConfig = serviceContext.DrsConfig
		if object != nil && object.IsManifest {
			accessMethod, err := buildCompoundManifestAccessMethod(serviceContext.DrsConfig, object)
			if err != nil {
				return DrsObject{}, err
			}
			accessMethods = []AccessMethod{accessMethod}
		} else {
			accessMethods = accessMethodsFromInternal(drs_support.BuildAccessMethodsWithFilesystem(serviceContext.DrsConfig, object, filesystem))
		}
	}

	aliases := append([]string(nil), object.Aliases...)
	if irodsURIAlias := buildAnonymousIRODSAliasURI(filesystem, object); irodsURIAlias != "" {
		alreadyPresent := false
		for _, alias := range aliases {
			if strings.EqualFold(strings.TrimSpace(alias), strings.TrimSpace(irodsURIAlias)) {
				alreadyPresent = true
				break
			}
		}
		if !alreadyPresent {
			aliases = append(aliases, irodsURIAlias)
		}
	}

	selfURI, err := buildSelfURI(drsConfig, object.Id)
	if err != nil {
		return DrsObject{}, fmt.Errorf("build self_uri for object %q: %w", strings.TrimSpace(object.Id), err)
	}

	response := DrsObject{
		Id:            object.Id,
		Name:          object.AbsolutePath,
		SelfUri:       selfURI,
		Size:          object.Size,
		CreatedTime:   object.CreatedTime,
		UpdatedTime:   object.UpdatedTime,
		Version:       object.Version,
		MimeType:      object.MimeType,
		AccessMethods: accessMethods,
		Description:   object.Description,
		Aliases:       aliases,
	}

	if object.Checksum != nil && object.Checksum.Value != "" {
		response.Checksums = []Checksum{{
			Checksum: object.Checksum.Value,
			Type_:    object.Checksum.Type,
		}}
	} else {
		response.Checksums = []Checksum{}
	}

	if expand && len(object.Contents) > 0 {
		response.Contents = make([]ContentsObject, 0, len(object.Contents))
		for _, entry := range object.Contents {
			drsURIs, err := buildContentsDrsURIs(drsConfig, entry.ID)
			if err != nil {
				return DrsObject{}, fmt.Errorf("build content drs_uri for object %q: %w", strings.TrimSpace(entry.ID), err)
			}

			response.Contents = append(response.Contents, ContentsObject{
				Name:   entry.Name,
				Id:     entry.ID,
				DrsUri: drsURIs,
			})
		}
	}

	return response, nil
}

func buildAnonymousIRODSAliasURI(filesystem drs_support.IRODSFilesystem, object *drs_support.InternalDrsObject) string {
	if filesystem == nil || object == nil {
		return ""
	}

	absolutePath := strings.TrimSpace(object.AbsolutePath)
	if absolutePath == "" {
		return ""
	}

	account := filesystem.GetAccount()
	if account == nil {
		return ""
	}

	uri, err := extension_irodsuri.BuildForAccountWithoutUserInfo(account, absolutePath)
	if err != nil || uri == nil {
		return ""
	}
	return uri.String()
}

func accessMethodsFromInternal(methods []drs_support.DrsAccessMethod) []AccessMethod {
	if len(methods) == 0 {
		return nil
	}

	response := make([]AccessMethod, 0, len(methods))
	for _, method := range methods {
		accessMethod := AccessMethod{
			Type_:     method.Type,
			AccessId:  method.AccessID,
			Cloud:     method.Cloud,
			Region:    method.Region,
			Available: method.Available,
		}

		if method.URL != "" {
			accessMethod.AccessUrl = &AllOfAccessMethodAccessUrl{
				Url: method.URL,
			}
		}

		if len(method.SupportedAuthTypes) > 0 || len(method.BearerAuthIssuers) > 0 {
			accessMethod.Authorizations = &AllOfAccessMethodAuthorizations{
				SupportedTypes:    append([]string(nil), method.SupportedAuthTypes...),
				BearerAuthIssuers: append([]string(nil), method.BearerAuthIssuers...),
			}
		}

		response = append(response, accessMethod)
	}

	return response
}

func buildCompoundManifestAccessMethod(drsConfig *drs_support.DrsConfig, object *drs_support.InternalDrsObject) (AccessMethod, error) {
	region := ""
	zone := ""
	if object != nil {
		region = strings.TrimSpace(object.ResourceName)
		zone = strings.TrimSpace(object.IrodsZone)
	}
	issuers := []string{}
	if issuer := bearerAuthIssuerFromConfig(drsConfig); issuer != "" {
		issuers = append(issuers, issuer)
	}
	compoundPath := "/ga4gh/drs/v1/ext/compound/"
	if object != nil {
		compoundPath = compoundPath + neturl.PathEscape(strings.TrimSpace(object.Id))
	}

	compoundURL, err := buildPublicAbsoluteURL(drsConfig, compoundPath)
	if err != nil {
		return AccessMethod{}, fmt.Errorf("build compound manifest access_url: %w", err)
	}

	return AccessMethod{
		Type_:     "https",
		AccessUrl: &AllOfAccessMethodAccessUrl{Url: compoundURL},
		Cloud:     "irods:" + zone,
		Region:    region,
		Available: false,
		Authorizations: &AllOfAccessMethodAuthorizations{
			SupportedTypes:    []string{"BasicAuth", "BearerAuth"},
			BearerAuthIssuers: issuers,
		},
	}, nil
}

func buildSelfURI(drsConfig *drs_support.DrsConfig, objectID string) (string, error) {
	objectID = strings.TrimSpace(objectID)
	if objectID == "" {
		return "", fmt.Errorf("missing object id")
	}

	baseURL, err := publicBaseURLFromConfig(drsConfig)
	if err != nil {
		return "", err
	}

	return fmt.Sprintf("drs://%s/%s", baseURL.Host, objectID), nil
}

func buildPublicAbsoluteURL(drsConfig *drs_support.DrsConfig, targetPath string) (string, error) {
	targetPath = "/" + strings.TrimPrefix(strings.TrimSpace(targetPath), "/")
	if strings.TrimSpace(targetPath) == "/" {
		return "", fmt.Errorf("missing target path")
	}

	baseURL, err := publicBaseURLFromConfig(drsConfig)
	if err != nil {
		return "", err
	}

	resolvedTarget, err := neturl.Parse(targetPath)
	if err != nil {
		return "", fmt.Errorf("invalid target path %q: %w", targetPath, err)
	}
	if resolvedTarget.Scheme != "" || resolvedTarget.Host != "" {
		return "", fmt.Errorf("target path must be relative to configured public URL")
	}

	return baseURL.ResolveReference(resolvedTarget).String(), nil
}

func publicBaseURLFromConfig(drsConfig *drs_support.DrsConfig) (*neturl.URL, error) {
	if drsConfig == nil {
		return nil, fmt.Errorf("missing DRS config")
	}

	rawPublicURL := strings.TrimSpace(drsConfig.PublicURL)
	if rawPublicURL == "" {
		return nil, fmt.Errorf("PublicURL must be configured")
	}

	parsed, err := neturl.Parse(rawPublicURL)
	if err != nil {
		return nil, fmt.Errorf("invalid PublicURL %q: %w", rawPublicURL, err)
	}

	scheme := strings.ToLower(strings.TrimSpace(parsed.Scheme))
	if scheme != "http" && scheme != "https" {
		return nil, fmt.Errorf("PublicURL must use http or https scheme")
	}
	if strings.TrimSpace(parsed.Host) == "" {
		return nil, fmt.Errorf("PublicURL must include host")
	}
	if parsed.User != nil {
		return nil, fmt.Errorf("PublicURL must not include user info")
	}
	if strings.TrimSpace(parsed.RawQuery) != "" || strings.TrimSpace(parsed.Fragment) != "" {
		return nil, fmt.Errorf("PublicURL must not include query or fragment")
	}
	if path := strings.TrimSpace(parsed.Path); path != "" && path != "/" {
		return nil, fmt.Errorf("PublicURL must not include a path")
	}

	return &neturl.URL{
		Scheme: scheme,
		Host:   strings.TrimSpace(parsed.Host),
	}, nil
}

func buildContentsDrsURIs(drsConfig *drs_support.DrsConfig, objectID string) ([]string, error) {
	objectID = strings.TrimSpace(objectID)
	if objectID == "" {
		return nil, nil
	}

	selfURI, err := buildSelfURI(drsConfig, objectID)
	if err != nil {
		return nil, err
	}

	return []string{selfURI}, nil
}

func authorizationsFromConfig(objectID string, drsConfig *drs_support.DrsConfig) Authorizations {
	response := Authorizations{
		DrsObjectId:    strings.TrimSpace(objectID),
		SupportedTypes: []string{"BasicAuth", "BearerAuth"},
	}

	if issuer := bearerAuthIssuerFromConfig(drsConfig); issuer != "" {
		response.BearerAuthIssuers = []string{issuer}
	}

	return response
}

func bulkAuthorizationsFromIDs(filesystem RouteFileSystem, drsConfig *drs_support.DrsConfig, objectIDs []string) (*InlineResponse2002, error) {
	resolved := make([]Authorizations, 0, len(objectIDs))
	missingIDs := make([]string, 0)

	for _, objectID := range objectIDs {
		if _, err := drs_support.GetDrsObjectByID(filesystem, filesystem, objectID); err != nil {
			if strings.Contains(err.Error(), "not found") {
				missingIDs = append(missingIDs, objectID)
				continue
			}

			return nil, fmt.Errorf("resolve DRS object %q: %w", objectID, err)
		}

		resolved = append(resolved, authorizationsFromConfig(objectID, drsConfig))
	}

	response := &InlineResponse2002{
		Summary: &Summary{
			Requested:  int32(len(objectIDs)),
			Resolved:   int32(len(resolved)),
			Unresolved: int32(len(missingIDs)),
		},
		ResolvedDrsObject: resolved,
	}

	if len(missingIDs) > 0 {
		unresolved := []UnresolvedInner{{
			ErrorCode: http.StatusNotFound,
			ObjectIds: append([]string(nil), missingIDs...),
		}}
		response.UnresolvedDrsObjects = &unresolved
	}

	return response, nil
}

func normalizedBulkObjectIDs(objectIDs []string) []string {
	resolved := make([]string, 0, len(objectIDs))
	for _, objectID := range objectIDs {
		objectID = strings.TrimSpace(objectID)
		if objectID == "" {
			continue
		}
		resolved = append(resolved, objectID)
	}

	return resolved
}

func validateConfiguredHTTPSProvider(drsConfig *drs_support.DrsConfig) error {
	if drsConfig == nil || !drsConfig.HttpsAccessMethodSupported {
		return nil
	}

	switch drs_support.EffectiveHTTPSAccessProvider(drsConfig.HttpsAccessImplementation) {
	case drs_support.HTTPSProviderIRODSGoREST, drs_support.HTTPSProviderIRODSHTTPSAPI:
		return nil
	default:
		return fmt.Errorf("unsupported https access provider %q", drsConfig.HttpsAccessImplementation)
	}
}

func bearerAuthIssuerFromConfig(drsConfig *drs_support.DrsConfig) string {
	if drsConfig == nil {
		return ""
	}

	baseURL := strings.TrimRight(strings.TrimSpace(drsConfig.OidcUrl), "/")
	if baseURL == "" {
		return ""
	}

	realm := strings.TrimSpace(drsConfig.OidcRealm)
	if realm == "" {
		return baseURL
	}

	return baseURL + "/realms/" + neturl.PathEscape(realm)
}
